package com.facilcomanda.orderservice.client; import com.facilcomanda.common.config.FeignConfig; import com.facilcomanda.common.dto.TableResponse; import org.springframework.cloud.openfeign.FeignClient; import org.springframework.web.bind.annotation.*; @FeignClient(name="table-service", configuration=FeignConfig.class) public interface TableClient { @PostMapping("/api/tables/internal/{id}/occupy") TableResponse occupy(@PathVariable Long id, @RequestHeader("X-Organization-ID") Long org); @GetMapping("/api/tables/internal/{id}") TableResponse get(@PathVariable Long id, @RequestHeader("X-Organization-ID") Long org); }
